<!--
使用场景：浏览器记住密码之后，不希望密码框提示账号密码
1 关于浏览器密码提示的一些特征
    a) 只有type=“password”时，浏览器会给出记录的密码自动填充选项；
    且存在type为password，重置为text时，浏览器仍然会给出记录的密码自动填充选项；
    b) 输入值后，浏览器密码自动填充选项会消失；
    c) 点击一次选项后，其它的type=“password”的输入框不再出现密码自动填充选项；
思路：
主要利用第1点和第2点特征
设置初始type为text，在输入值后将type设置为password，
在清空值时将type为text，并将该输入框dom结点销毁重建。
-->

<template>
	<el-input
		ref="confirmPassword"
		v-if="hackConfirmPassword"
		:show-password="showConfirmPassword"
		autocomplete="new-password"
		@input="
			value => {
				showPassword(value);
			}
		"
		prefix-icon="el-icon-lock"
		:placeholder="placeholder"
		v-model.trim="password"
		maxlength="20"
	></el-input>
</template>

<script>
export default {
	name: 'Password',
	props: {
		placeholder: { type: String, default: '请输入密码' },
	},
	data() {
		return {
			showConfirmPassword: false,
			hackConfirmPassword: true,
			password: '',
		};
	},
	methods: {
		showPassword(value) {
			if (value !== '' && !this.showConfirmPassword) {
				// 输入数据时,将type设为password
				this.showConfirmPassword = true;
			} else if (value === '' && this.showConfirmPassword) {
				// 清空数据时,将组件销毁，type设为text。再重新渲染组件，并获取焦点
				this.hackConfirmPassword = false;
				this.showConfirmPassword = false;
				this.$nextTick(() => {
					this.hackConfirmPassword = true;
					setTimeout(() => {
						this.$refs.confirmPassword.$el.children[0].focus();
					}, 5);
				});
			}
			this.$emit('input', value);
		},
	},
};
</script>

